package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"net/http"
	"net/url"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// 1. Generate cryptographically secure random state
	state, err := generateRandomState(32)
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %v", err)
	}

	// 2. Validate redirectPath to prevent open redirect attacks
	if err := validateRedirectPath(redirectPath); err != nil {
		return "", fmt.Errorf("invalid redirect path: %v", err)
	}

	// 3. Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// 4. Generate the authorization URL with PKCE support
	verifier := oauth2.GenerateVerifier()
	authURL := config.AuthCodeURL(state, oauth2.AccessTypeOnline, oauth2.S256ChallengeOption(verifier))

	// 5. Store both state and code_verifier securely
	// Store state in HTTP-only, Secure cookie
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes expiration
	})

	// Store code_verifier in HTTP-only, Secure cookie
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_code_verifier",
		Value:    verifier,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes expiration
	})

	return authURL, nil
}

// generateRandomState generates a cryptographically secure random state string
func generateRandomState(length int) (string, error) {
	bytes := make([]byte, length)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return base64.RawURLEncoding.EncodeToString(bytes), nil
}

// validateRedirectPath validates the redirect path to prevent open redirect attacks
func validateRedirectPath(redirectPath string) error {
	// Parse the redirect URL
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return fmt.Errorf("invalid URL format: %v", err)
	}

	// Ensure the URL is absolute
	if !parsedURL.IsAbs() {
		return fmt.Errorf("redirect URL must be absolute")
	}

	// Validate scheme - should be HTTPS in production
	if parsedURL.Scheme != "https" && parsedURL.Scheme != "http" {
		return fmt.Errorf("redirect URL must use HTTPS or HTTP")
	}

	// Validate host - ensure it's a trusted domain
	allowedDomains := []string{
		"yourapp.com",
		"app.yourapp.com",
		// Add other trusted subdomains here
	}

	hostValid := false
	host := parsedURL.Hostname()
	for _, domain := range allowedDomains {
		if host == domain || (len(host) >= len(domain) && (host == domain || host[len(host)-len(domain):] == domain && (len(host) == len(domain) || host[len(host)-len(domain)-1] == '.'))) {
			hostValid = true
			break
		}
	}

	if !hostValid {
		return fmt.Errorf("redirect URL host not allowed")
	}

	// Additional security checks
	// Prevent redirects to localhost or internal networks
	if host == "localhost" || host == "127.0.0.1" || host == "::1" {
		return fmt.Errorf("redirect to localhost not allowed")
	}

	return nil
}

